     3→/** AST class definitions */
     4→
     5→/** The AST type which support a visitor interface */
     6→interface AST {
     7→  public <ResType> ResType accept(ASTVisitor<ResType> v);
     8→}
     9→
    10→interface ASTVisitor<ResType> {
    11→  ResType forBoolConstant(BoolConstant b);
    12→  ResType forIntConstant(IntConstant i);
    13→  ResType forEmptyConstant(EmptyConstant n);
    14→  ResType forJamEmpty(JamEmpty je);
    15→  ResType forVariable(Variable v);
    16→  ResType forPrimFun(PrimFun f);
    17→  ResType forUnOpApp(UnOpApp u);
    18→  ResType forBinOpApp(BinOpApp b);
    19→  ResType forApp(App a);
    20→  ResType forMap(Map m);
    21→  ResType forIf(If i);
    22→  ResType forLet(Let l);
    23→}
    24→
    25→/* The Term interface correspond to AST's that when output as concrete syntax by toString() can be used as terms 
    26→ * in an iterative binary expression without enclosing parentheses. We enclose all binary expressions in parentheses
    27→ * so we do not presume either left or right associativity for infix binary operators. */
    28→/** Term ::= Constant | PrimFun | Variable | UnOpApp |  App */
    29→interface Term extends AST {}
    30→
    31→/* NOTE: all Constant objects belong to the types Token and AST; Constant tokens evaluate to themselves.
    32→ * The variant classes (IntConstant, BoolConstant, JamEmpty) are defined in the file  ValuesTokens.java */
    33→
    34→/** Constant ::= IntConstant | BoolConstant | EmptyConstant */
    35→interface Constant extends Term {}
