    37→/** UnOp ::= UnOpPlus | UnOpMinus | OpTilde */
    38→/** Class representing the unary operator within a UnOppApp. */
    39→abstract class UnOp {
    40→  String name;
    41→  public UnOp(String s) { name = s; }
    42→  public String toString() { return name; }
    43→  public abstract <ResType> ResType accept(UnOpVisitor<ResType> v);
    44→}
    45→
    46→/** Visitor for the UnOp union type. */
    47→interface UnOpVisitor<ResType> {
    48→  ResType forUnOpPlus(UnOpPlus op);
