    50→  ResType forOpTilde(OpTilde op);
    51→  // ResType forOpBang(OpBang op);  // Supports ref cell extension to Jam
    52→  // ResType forOpRef(OpRef op);    // Supports ref cell extension to Jam
    53→}
    54→
    55→/** BinOp ::= BinOpPlus | BinOpMinus | OpTimes | OpDivide | OpEquals | OpNotEquals | OpLessThan | OpGreaterThan |
    56→  *           OpLessThanOrEquals OpGreaterThanOrEquals | OpAnd | OpOr */
    57→
    58→/** Class representing the binary operator within a BinOppApp. */
    59→abstract class BinOp {
