   344→  private OpToken(String s, boolean iu, boolean ib, UnOp u, BinOp b) {
   345→    symbol = s; isUnOp = iu; isBinOp = ib; unOp = u; binOp = b; 
   346→  }
   347→  
   348→  /** factory method for constructing OpToken serving as both UnOp and BinOp */
