/** Parser for Assignment 1 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {

  private Lexer in;

  Parser(Lexer i) {
    in = i;
  }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp) */
  public AST parse() throws ParseException {
    AST result = parseExp();
    if (in.peek() != null) {
      throw new ParseException("Unexpected token after expression: " + in.peek());
    }
    return result;
  }

  /** Parses:
    *   <exp> :: = if <exp> then <exp> else <exp>
    *            | let <prop-def-list> in <exp>
    *            | map <id-list> to <exp>
    *            | <term> { <biop> <term> }*  // (left associatively!)
    */
  private AST parseExp() {
    Token t = in.peek();

    if (t == Lexer.IF) {
      in.readToken();  // consume 'if'
      AST test = parseExp();
      if (in.peek() != Lexer.THEN) {
        throw new ParseException("Expected 'then' after if condition");
      }
      in.readToken();  // consume 'then'
      AST conseq = parseExp();
      if (in.peek() != Lexer.ELSE) {
        throw new ParseException("Expected 'else' after then branch");
      }
      in.readToken();  // consume 'else'
      AST alt = parseExp();
      return new If(test, conseq, alt);
    }

    if (t == Lexer.LET) {
      in.readToken();  // consume 'let'
      Def[] defs = parseDefList();
      if (in.peek() != Lexer.IN) {
        throw new ParseException("Expected 'in' after definitions");
      }
      in.readToken();  // consume 'in'
      AST body = parseExp();
      return new Let(defs, body);
    }

    if (t == Lexer.MAP) {
      in.readToken();  // consume 'map'
      Variable[] vars = parseIdList();
      if (in.peek() != Lexer.TO) {
        throw new ParseException("Expected 'to' after id list");
      }
      in.readToken();  // consume 'to'
      AST body = parseExp();
      return new Map(vars, body);
    }

    // Otherwise parse binary expression: Term { BinOp Term }*
    return parseBinExp();
  }

  /** Parses a binary expression with left-associativity:
    * Term { BinOp Term }*
    */
  private AST parseBinExp() {
    AST left = parseTerm();
    while (isBinOp(in.peek())) {
      Token opToken = in.readToken();
      BinOp op = ((OpToken) opToken).toBinOp();
      AST right = parseTerm();
      left = new BinOpApp(op, left, right);
    }
    return left;
  }

  /** Returns true if token t is a binary operator */
  private boolean isBinOp(Token t) {
    if (t instanceof OpToken) {
      return ((OpToken) t).isBinOp();
    }
    return false;
  }

  /** Parses a Term:
    * <term> ::= <unop> <term>
    *          | <factor> { ( <exp-list> ) }
    *          | <empty>
    *          | <int>
    *          | <bool>
    */
  private AST parseTerm() {
    Token t = in.peek();

    // Check for unary operator
    if (t instanceof OpToken && ((OpToken) t).isUnOp()) {
      Token opToken = in.readToken();
      UnOp op = ((OpToken) opToken).toUnOp();
      AST arg = parseTerm();
      return new UnOpApp(op, arg);
    }

    // Parse factor with possible function applications
    AST rator = parseFactor();

    // Handle function applications: ( ExpList )
    while (in.peek() == LeftParen.ONLY) {
      in.readToken();  // consume '('
      AST[] args = parseExpList();
      if (in.peek() != RightParen.ONLY) {
        throw new ParseException("Expected ')' after argument list");
      }
      in.readToken();  // consume ')'
      rator = new App(rator, args);
    }

    return rator;
  }

  /** Parses a Factor:
    * <factor> ::= ( <exp> ) | <prim> | <id>
    */
  private AST parseFactor() {
    Token t = in.peek();

    if (t == LeftParen.ONLY) {
      in.readToken();  // consume '('
      AST exp = parseExp();
      if (in.peek() != RightParen.ONLY) {
        throw new ParseException("Expected ')' after expression");
      }
      in.readToken();  // consume ')'
      return exp;
    }

    if (t instanceof PrimFun) {
      in.readToken();
      return (PrimFun) t;
    }

    if (t instanceof Variable) {
      in.readToken();
      return (Variable) t;
    }

    if (t instanceof Constant) {
      in.readToken();
      return (Constant) t;
    }

    throw new ParseException("Expected factor but got: " + t);
  }

  /** Parses an expression list:
    * <exp-list> ::= { <prop-exp-list> }
    * <prop-exp-list> ::= <exp> { , <exp> }*
    */
  private AST[] parseExpList() {
    if (in.peek() == RightParen.ONLY) {
      return new AST[0];  // empty list
    }

    List<AST> exps = new ArrayList<AST>();
    exps.add(parseExp());
    while (in.peek() == Comma.ONLY) {
      in.readToken();  // consume ','
      exps.add(parseExp());
    }
    return exps.toArray(new AST[exps.size()]);
  }

  /** Parses an id list:
    * <id-list> ::= { <prop-id-list> }
    * <prop-id-list> ::= <id> { , <id> }*
    */
  private Variable[] parseIdList() {
    Token t = in.peek();
    if (!(t instanceof Variable)) {
      throw new ParseException("Expected variable in id list but got: " + t);
    }

    List<Variable> ids = new ArrayList<Variable>();
    ids.add((Variable) in.readToken());
    while (in.peek() == Comma.ONLY) {
      in.readToken();  // consume ','
      t = in.peek();
      if (!(t instanceof Variable)) {
        throw new ParseException("Expected variable after comma but got: " + t);
      }
      ids.add((Variable) in.readToken());
    }
    return ids.toArray(new Variable[ids.size()]);
  }

  /** Parses a definition list:
    * <def>+ where <def> ::= <id> := <exp> ;
    */
  private Def[] parseDefList() {
    List<Def> defs = new ArrayList<Def>();
    while (true) {
      Token t = in.peek();
      if (!(t instanceof Variable)) {
        throw new ParseException("Expected variable in definition but got: " + t);
      }
      Variable var = (Variable) in.readToken();
      if (in.peek() != Lexer.BIND) {
        throw new ParseException("Expected ':=' after variable in definition");
      }
      in.readToken();  // consume ':='
      AST value = parseExp();
      if (in.peek() != SemiColon.ONLY) {
        throw new ParseException("Expected ';' after definition");
      }
      in.readToken();  // consume ';'
      defs.add(new Def(var, value));

      // Check if there's another definition or if we're done
      Token nextToken = in.peek();
      if (nextToken == Lexer.IN || nextToken == null) {
        break;
      }
      if (!(nextToken instanceof Variable)) {
        break;
      }
    }
    if (defs.isEmpty()) {
      throw new ParseException("Expected at least one definition after 'let'");
    }
    return defs.toArray(new Def[defs.size()]);
  }
}

